// src/components/Hero.jsx
// ─────────────────────────────────────────────
// INSTRUCCIONES:
// 1. Copia tu vídeo a /public/hero-video.mp4
// 2. Copia tu foto a /public/foto.jpg
//    (si el nombre es distinto, cámbialo en la línea marcada con 📷)
// ─────────────────────────────────────────────

export default function Hero() {
  return (
    <section id="hero" style={s.section}>

      {/* ── Vídeo de fondo ── */}
      <video autoPlay loop muted playsInline style={s.videoBg}>
        <source src="/hero-video.mp4" type="video/mp4" />
      </video>

      {/* Overlay degradado */}
      <div style={s.overlay} />

      {/* Grid sutil */}
      <div style={s.bgGrid} />

      {/* ── Layout principal ── */}
      <div style={s.layout}>

        {/* ── IZQUIERDA ── */}
        <div style={s.left}>

          {/* Badge */}
          <div style={s.badge}>
